const results = items[0].json.results || [];

return results.map(r => {
  const rawDate = r.date || r.dateCreated;
  const date = rawDate && typeof rawDate === 'string' && rawDate.includes('T') ? rawDate.split('T')[0] : rawDate;
  const pessoa = (r.description || r.merchantName || r.paymentData?.payer?.name || 'Transação sem descrição').trim();
  const paymentMethod = r.paymentData?.paymentMethod ?? '';
  const descricao = paymentMethod;
  const amount = Math.abs(parseFloat(r.amount) || 0);
  const originalAmount = parseFloat(r.amount) || 0;
  const tipo = originalAmount >= 0 ? 'entrada' : 'saida';
  const id_unico = `${rawDate || date}-${pessoa}-${amount}`;

  return {
    json: {
      data: date,
      descricao: descricao || '',
      valor: amount,
      tipo: tipo || 'saida',
      pessoa: pessoa || '',
      id_unico: id_unico,
      categoria: paymentMethod || ''
    }
  };
});

const input = $input.item.json;

// Pegar apiKey - pode vir como string ou objeto
let apiKey = input.apiKey;
if (typeof apiKey === 'object' && apiKey !== null) {
  apiKey = apiKey.token || apiKey.apiKey || JSON.stringify(apiKey);
}
apiKey = String(apiKey || '');

// Remover caracteres inválidos para headers (newline, tab, aspas, etc)
const cleanApiKey = String(apiKey || '').replace(/[\r\n\t"'\x00]/g, '').trim();
// Pegar itemId
const itemId = input.itemId || input.id || '';

// Pegar accountId
const accountId = input.accountId || input.id || '';

// Pegar datas do node "Pegar última data"
let fromDate = input.fromDate;
let toDate = input.toDate;
if (!fromDate || !toDate) {
  try {
    const datasNode = $('Pegar última data').item.json;
    fromDate = datasNode.fromDate || fromDate;
    toDate = datasNode.toDate || toDate;
  } catch (e) {
    const hoje = new Date();
    const trintaDiasAtras = new Date();
    trintaDiasAtras.setDate(hoje.getDate() - 30);
    fromDate = fromDate || trintaDiasAtras.toISOString().split('T')[0];
    toDate = toDate || hoje.toISOString().split('T')[0];
  }
}

  if (!fromDate || !toDate) {
    const hoje = new Date();
    const trintaDiasAtras = new Date();
    trintaDiasAtras.setDate(hoje.getDate() - 30);
    fromDate = fromDate || trintaDiasAtras.toISOString().split('T')[0];
    toDate = toDate || hoje.toISOString().split('T')[0];
  }

return {
  json: {
    apiKey: cleanApiKey,
    itemId: itemId,
    accountId: accountId,
    fromDate: fromDate,
    toDate: toDate
  }
};

const items = $input.all();

// Se não tem transações (tabela vazia), usa últimos 30 dias
if (items.length === 0) {
  const hoje = new Date();
  const trintaDiasAtras = new Date();
  trintaDiasAtras.setDate(hoje.getDate() - 30);

  return {
    json: {
      fromDate: trintaDiasAtras.toISOString().split('T')[0],
      toDate: hoje.toISOString().split('T')[0]
    }
  };
}

// Ordena por data (mais recente primeiro)
const sorted = items.sort((a, b) => {
  const dateA = new Date(a.json.data || 0);
  const dateB = new Date(b.json.data || 0);
  return dateB - dateA;
});

// Pega a data da mais recente
const lastDate = new Date(sorted[0].json.data);
const hoje = new Date();

// fromDate = dia seguinte à última transação (para não repetir)
lastDate.setDate(lastDate.getDate() + 1);
const fromDate = lastDate.toISOString().split('T')[0];
const toDate = hoje.toISOString().split('T')[0];

return {
  json: {
    fromDate: fromDate,
    toDate: toDate
  }
};

const hoje = new Date();
const trintaDiasAtras = new Date();
trintaDiasAtras.setDate(hoje.getDate() - 30);

return {
  json: {
    fromDate: trintaDiasAtras.toISOString().split('T')[0] + 'T00:00:00.000Z',
    toDate: hoje.toISOString().split('T')[0] + 'T23:59:59.999Z'
  }
};
